import{_ as r,o as a,c as s,ah as t}from"./chunks/framework.Be4cSgRn.js";const u=JSON.parse('{"title":"Fase 6: Automatisering & Infrastructure-as-Code","description":"","frontmatter":{"title":"Fase 6: Automatisering & Infrastructure-as-Code","phase":6,"topic":"automatisering","personas":["arkitekt","driftsleder"],"tags":["IaC","CI/CD","VM-skabeloner","servicekatalog","self-service","konfigurationsdrift"],"priority":"parallel","dependencies":[2,3]},"headers":[],"relativePath":"faser/06-iac.md","filePath":"faser/06-iac.md"}'),i={name:"faser/06-iac.md"};function n(o,e,l,d,p,g){return a(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="fase-6-automatisering-infrastructure-as-code" tabindex="-1">Fase 6: Automatisering &amp; Infrastructure-as-Code <a class="header-anchor" href="#fase-6-automatisering-infrastructure-as-code" aria-label="Permalink to &quot;Fase 6: Automatisering &amp; Infrastructure-as-Code&quot;">​</a></h1><div class="phase-meta"><span><strong>Sti:</strong> <span class="parallel-badge">Parallel</span></span><span><strong>Afhænger af:</strong> Design fra dag 1; deployment kræver Fase 2+3</span><span><strong>Skal være klar inden:</strong> Fase 9</span></div><div class="persona-badges"><span class="persona-badge arkitekt">🏗️ Arkitekt</span><span class="persona-badge driftsleder">⚙️ Driftsleder</span></div><p>Det forventes, at automatisering ikke er et efterfølgende optimeringsprojekt, men en grundlæggende designbeslutning fra dag ét. Al infrastruktur skal være reproducerbar fra kode, og manuelle ændringer skal være undtagelsen.</p><ul><li><p>Al infrastrukturkonfiguration (compute, netværk, storage, sikkerhed) defineres som kode i et versionsstyringssystem og udrulles via automatiserede CI/CD-pipelines.</p></li><li><p>Standardiserede, hærdede VM-skabeloner etableres i et fælles servicekatalog med defineret livscyklus, versionsstyring og automatiseret opdatering.</p></li><li><p>Automatiseret provisioneringsworkflow implementeres, så oprettelse af et komplet tenant-miljø (compute, netværk, segmentering, monitorering, backup) kan ske inden for minutter.</p></li><li><p>Konfigurationsdrift-detektion etableres, så platformen automatisk identificerer og korrigerer afvigelser fra den godkendte konfiguration.</p></li><li><p>Self-service-portal konfigureres for standardiserede tenant-forespørgsler med automatiseret godkendelsesflow, compliance-validering og provisionering.</p></li></ul>',5)])])}const c=r(i,[["render",n]]);export{u as __pageData,c as default};
